import { useState, useEffect, useRef } from "react";
import "@/App.css";
import { motion, useInView } from "framer-motion";
import { 
  ArrowRight, 
  Phone, 
  Check, 
  X, 
  Radar, 
  Camera, 
  Cpu, 
  Trophy,
  Star,
  Nfc,
  ShieldCheck,
  MapPin,
  TrendingUp,
  ChevronDown
} from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";

// Animation variants
const fadeInUp = {
  initial: { opacity: 0, y: 30 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.6, ease: [0.22, 1, 0.36, 1] }
};

const staggerContainer = {
  animate: {
    transition: {
      staggerChildren: 0.1
    }
  }
};

// Branded Section Header Component
const SectionHeader = ({ number, label, title, highlight, description, centered = true }) => (
  <motion.div 
    initial={{ opacity: 0, y: 30 }}
    whileInView={{ opacity: 1, y: 0 }}
    viewport={{ once: true }}
    transition={{ duration: 0.6 }}
    className={centered ? "text-center mb-8 md:mb-16" : "mb-8 md:mb-16"}
  >
    <div className={`kapta-section-marker ${centered ? "justify-center" : ""}`}>
      <span className="font-mono text-[10px] sm:text-xs text-[#1c3ff9] tracking-widest">{number}</span>
      <span className="font-mono text-[10px] sm:text-xs text-[#A1A1AA] uppercase tracking-widest">{label}</span>
    </div>
    <h2 className="text-2xl sm:text-3xl md:text-4xl lg:text-5xl font-bold text-[#0A0A0A] mb-2 md:mb-4 leading-tight">
      {title} <span className="text-[#1c3ff9]">{highlight}</span>
    </h2>
    {description && (
      <p className="text-sm md:text-base lg:text-lg text-[#52525B] max-w-2xl mx-auto px-4 md:px-0">
        {description}
      </p>
    )}
  </motion.div>
);

// Navbar Component
const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <motion.nav
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.6 }}
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        scrolled ? "glassmorphism shadow-premium" : "bg-transparent"
      }`}
      data-testid="navbar"
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16 md:h-20">
          <a href="#" className="flex items-center gap-2" data-testid="logo">
            <img 
              src="https://customer-assets.emergentagent.com/job_e9af3148-6038-40b0-a95f-b7160e86bcee/artifacts/v4yy8wt0_logo2.webp" 
              alt="KAPTA" 
              className="h-6 sm:h-8 md:h-10 w-auto"
            />
            <div className="flex items-baseline gap-0.5">
              <span className="text-lg sm:text-xl md:text-2xl font-black tracking-tight text-[#0A0A0A]" style={{ fontFamily: 'Space Grotesk, sans-serif', fontWeight: '900', letterSpacing: '-0.02em', fontSize: 'clamp(1.1em, 2.5vw, 1.3em)' }}>KAPTA</span>
              <span className="text-sm sm:text-base md:text-lg font-medium italic text-[#1c3ff9]" style={{ 
                fontFamily: 'Inter, sans-serif', 
                textShadow: '0 0 3px rgba(28, 63, 249, 0.4), 0 0 6px rgba(28, 63, 249, 0.2)',
                filter: 'brightness(1.1)'
              }}>media</span>
            </div>
          </a>

          <div className="hidden md:flex items-center gap-8">
            <a href="#mechanism" className="text-sm font-medium text-[#52525B] hover:text-[#0A0A0A] transition-colors">
              Mécanisme
            </a>
            <a href="#pricing" className="text-sm font-medium text-[#52525B] hover:text-[#0A0A0A] transition-colors">
              Tarifs
            </a>
            <a href="#faq" className="text-sm font-medium text-[#52525B] hover:text-[#0A0A0A] transition-colors">
              FAQ
            </a>
            <Button 
              data-testid="cta-audit-desktop"
              className="bg-[#1c3ff9] hover:bg-[#1534d4] text-white rounded-full px-6 btn-shimmer"
              onClick={() => document.getElementById('contact')?.scrollIntoView({ behavior: 'smooth' })}
            >
              AUDIT GRATUIT
            </Button>
          </div>

          <a
            href="tel:0686018054"
            className="md:hidden flex items-center justify-center w-12 h-12 rounded-full bg-[#1c3ff9] text-white shadow-glow-sm"
            data-testid="cta-phone-mobile"
          >
            <Phone className="w-5 h-5" />
          </a>
        </div>
      </div>
    </motion.nav>
  );
};

// Hero Section - Clean & Visual with Google Maps Mockup
const Hero = () => {
  return (
    <section 
      className="relative min-h-screen pt-24 md:pt-28 pb-16 md:pb-20 overflow-hidden bg-white"
      data-testid="hero-section"
    >
      {/* Strong Grid Background */}
      <div className="absolute inset-0 bg-[linear-gradient(rgba(28,63,249,0.08)_1px,transparent_1px),linear-gradient(90deg,rgba(28,63,249,0.08)_1px,transparent_1px)] bg-[size:40px_40px]" />

      {/* Gradient overlay for depth */}
      <div className="absolute inset-0 bg-gradient-to-b from-white via-transparent to-white pointer-events-none" />

      {/* Soft Blue Glow */}
      <div className="absolute top-1/3 right-1/4 w-[500px] h-[500px] bg-[#1c3ff9]/10 rounded-full blur-[120px] pointer-events-none" />

      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid lg:grid-cols-2 gap-8 lg:gap-12 items-center">
          {/* Left - Text Content */}
          <div className="text-center lg:text-left order-1 lg:order-1">
            {/* Badge */}
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5 }}
              className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-[#1c3ff9]/5 border border-[#1c3ff9]/10 mb-6"
            >
              <span className="w-2 h-2 rounded-full bg-[#10B981] animate-pulse" />
              <span className="text-xs md:text-sm font-medium text-[#1c3ff9]">Top Google Maps en 14 jours</span>
            </motion.div>

            {/* Main Headline */}
            <motion.h1 
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: 0.1 }}
              className="text-4xl sm:text-5xl md:text-6xl font-bold text-[#0A0A0A] leading-[1.05] mb-6"
            >
              Votre concurrent est{" "}
              <span className="text-[#1c3ff9]">N°1</span>.
              <br />
              <span className="text-[#71717A]">Ça vous va ?</span>
            </motion.h1>

            {/* Subtitle */}
            <motion.p 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.2 }}
              className="text-base md:text-lg text-[#52525B] max-w-xl mb-6 leading-relaxed"
            >
              On vous met dans le <span className="font-semibold text-[#0A0A0A]">Top Google Maps</span> avec 
              une vidéo pro + une fiche Google qui donne envie d'appeler.
            </motion.p>

            {/* Price tag */}
            <motion.p 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ duration: 0.5, delay: 0.25 }}
              className="text-sm text-[#10B981] font-mono mb-6"
            >
              350€ · Résultats sous 30 jours ou remboursé
            </motion.p>

            {/* CTA */}
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.3 }}
              className="flex flex-col sm:flex-row items-center lg:items-start gap-4 mb-8"
            >
              <Button 
                data-testid="cta-hero-primary"
                size="lg"
                className="w-full sm:w-auto bg-[#1c3ff9] hover:bg-[#1534d4] text-white rounded-full px-8 py-6 text-base font-semibold shadow-glow btn-shimmer group"
                onClick={() => document.getElementById('contact')?.scrollIntoView({ behavior: 'smooth' })}
              >
                RÉSERVER MON AUDIT GRATUIT
                <ArrowRight className="ml-2 w-5 h-5 group-hover:translate-x-1 transition-transform" />
              </Button>
            </motion.div>

            {/* Stats Row */}
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.4 }}
              className="flex items-center justify-center lg:justify-start gap-8"
            >
              {[
                { value: "14j", label: "Résultats" },
                { value: "350€", label: "Tarif pilote" },
                { value: "5", label: "Places" },
              ].map((stat, i) => (
                <div key={i} className="text-center">
                  <p className="text-2xl md:text-3xl font-bold text-[#0A0A0A]">{stat.value}</p>
                  <p className="text-xs text-[#71717A]">{stat.label}</p>
                </div>
              ))}
            </motion.div>
          </div>

          {/* Right - Google Maps Mockup */}
          <motion.div 
            initial={{ opacity: 0, x: 50 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.8, delay: 0.3 }}
            className="relative order-2 lg:order-2"
          >
            {/* Phone Frame */}
            <div className="relative mx-auto w-[200px] sm:w-[280px] md:w-[320px] lg:w-[360px]">
              {/* Phone body */}
              <div className="relative bg-[#0A0A0A] rounded-[40px] p-2 shadow-2xl">
                {/* Screen */}
                <div className="bg-white rounded-[32px] overflow-hidden">
                  {/* Google Maps Header */}
                  <div className="bg-white px-4 py-3 border-b border-gray-100">
                    <div className="flex items-center gap-2">
                      <div className="w-8 h-8 rounded-full bg-[#4285F4] flex items-center justify-center">
                        <MapPin className="w-4 h-4 text-white" />
                      </div>
                      <div className="flex-1">
                        <div className="h-3 w-32 bg-gray-200 rounded" />
                        <div className="h-2 w-20 bg-gray-100 rounded mt-1" />
                      </div>
                    </div>
                  </div>

                  {/* Map placeholder */}
                  <div className="h-20 sm:h-32 bg-gradient-to-b from-[#E8F0E8] to-[#D4E4D4] relative">
                    <div className="absolute inset-0 opacity-30">
                      <div className="absolute top-4 left-4 w-16 h-1 bg-[#F9C74F] rounded" />
                      <div className="absolute top-8 left-8 w-24 h-1 bg-[#90BE6D] rounded" />
                      <div className="absolute top-12 right-4 w-12 h-1 bg-white rounded" />
                    </div>
                    {/* Location pin */}
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-full">
                      <div className="w-8 h-8 bg-[#EA4335] rounded-full flex items-center justify-center shadow-lg animate-bounce">
                        <div className="w-3 h-3 bg-white rounded-full" />
                      </div>
                      <div className="w-2 h-2 bg-[#EA4335]/50 rounded-full mx-auto -mt-1" />
                    </div>
                  </div>

                  {/* Business Results */}
                  <div className="p-2 sm:p-3 space-y-1 sm:space-y-2">
                    {/* Result 1 - YOUR BUSINESS - Highlighted */}
                    <div className="p-2 sm:p-3 rounded-xl bg-[#1c3ff9]/5 border-2 border-[#1c3ff9] relative">
                      <div className="absolute -top-2 -left-2 w-6 h-6 bg-[#1c3ff9] rounded-full flex items-center justify-center text-white text-xs font-bold">1</div>
                      <div className="flex gap-2 sm:gap-3">
                        <div className="w-12 h-12 sm:w-16 sm:h-16 rounded-lg bg-gradient-to-br from-[#1c3ff9]/20 to-[#1c3ff9]/10 flex items-center justify-center">
                          <Camera className="w-4 h-4 sm:w-6 sm:h-6 text-[#1c3ff9]" />
                        </div>
                        <div className="flex-1">
                          <p className="font-bold text-sm text-[#0A0A0A]">Votre Commerce</p>
                          <div className="flex items-center gap-1 mt-0.5">
                            {[...Array(5)].map((_, i) => (
                              <Star key={i} className="w-3 h-3 fill-[#FBBC04] text-[#FBBC04]" />
                            ))}
                            <span className="text-xs text-[#52525B] ml-1">4.9 (127)</span>
                          </div>
                          <p className="text-xs text-[#10B981] font-medium mt-1">● Ouvert · Ferme à 19h</p>
                        </div>
                      </div>
                    </div>

                    {/* Result 2 - Competitor (faded) */}
                    <div className="p-2 rounded-lg bg-gray-50 opacity-60">
                      <div className="flex gap-2 items-center">
                        <div className="w-2 h-2 rounded-full bg-gray-300 text-[10px]" />
                        <div className="w-10 h-10 rounded bg-gray-200" />
                        <div className="flex-1">
                          <div className="h-2.5 w-24 bg-gray-200 rounded" />
                          <div className="h-2 w-16 bg-gray-100 rounded mt-1" />
                        </div>
                      </div>
                    </div>

                    {/* Result 3 - Competitor (more faded) */}
                    <div className="p-2 rounded-lg bg-gray-50 opacity-40">
                      <div className="flex gap-2 items-center">
                        <div className="w-2 h-2 rounded-full bg-gray-300" />
                        <div className="w-10 h-10 rounded bg-gray-200" />
                        <div className="flex-1">
                          <div className="h-2.5 w-20 bg-gray-200 rounded" />
                          <div className="h-2 w-14 bg-gray-100 rounded mt-1" />
                        </div>
                      </div>
                    </div>
                  </div>
                </div>

                {/* Phone notch */}
                <div className="absolute top-0 left-1/2 -translate-x-1/2 w-24 h-6 bg-[#0A0A0A] rounded-b-2xl" />
              </div>

              {/* Floating badge */}
              <motion.div 
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{ opacity: 1, scale: 1 }}
                transition={{ duration: 0.5, delay: 0.8 }}
                className="absolute -top-4 -right-4 bg-[#10B981] text-white px-3 py-1.5 rounded-full text-xs font-bold shadow-lg"
              >
                Position N°1 ✓
              </motion.div>

              {/* Floating stats card */}
              <motion.div 
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ duration: 0.5, delay: 1 }}
                className="absolute -left-4 md:-left-12 top-1/3 bg-white rounded-xl p-3 shadow-xl border border-gray-100"
              >
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 rounded-lg bg-[#10B981]/10 flex items-center justify-center">
                    <TrendingUp className="w-4 h-4 text-[#10B981]" />
                  </div>
                  <div>
                    <p className="text-lg font-bold text-[#10B981]">+127%</p>
                    <p className="text-[10px] text-[#71717A]">Appels/mois</p>
                  </div>
                </div>
              </motion.div>
            </div>
          </motion.div>
        </div>
      </div>

      {/* Scroll Indicator */}
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 1.2 }}
        className="absolute bottom-6 left-1/2 -translate-x-1/2"
      >
        <motion.div
